export const DistribuzioneRisorsePage: React.FC = () => {
  const { state, dispatch, saveState } = useAppContext();
  const { fundData, calculatedFund, normativeData } = state;
  const { dettagli: employees } = state.personaleServizio;
  const [isMaggiorazioneUserEdited, setIsMaggiorazioneUserEdited] = useState(false);
  const [isOrganizzativaUserEdited, setIsOrganizzativaUserEdited] = useState(false);
  const [isIndividualeUserEdited, setIsIndividualeUserEdited] = useState(false);


  if (!calculatedFund || !calculatedFund.dettaglioFondi || !normativeData) {
    return (
      <div className="space-y-8">
        <h2 className="text-[#1b0e0e] tracking-light text-2xl sm:text-[30px] font-bold leading-tight">Distribuzione delle Risorse</h2>
        <Card title="Dati non disponibili">
          <p className="text-lg text-[#5f5252] mb-4">
            Per poter distribuire le risorse, ├¿ necessario prima eseguire il calcolo generale del fondo.
          </p>
          <p className="text-sm text-[#5f5252] mb-4">
            Vai alla pagina <strong className="text-[#1b0e0e]">"Dati Costituzione Fondo"</strong> e clicca sul pulsante <strong className="text-[#ea2832]">"Salva Dati e Calcola Fondo"</strong>.
          </p>
          <Button 
            variant="primary" 
            onClick={() => dispatch({ type: 'SET_ACTIVE_TAB', payload: 'dataEntry' })}
          >
            Vai a Dati Costituzione Fondo
          </Button>
        </Card>
      </div>
    );
  }

  const {
    distribuzioneRisorseData,
    fondoAccessorioDipendenteData,
    annualData,
    fondoElevateQualificazioniData,
  } = fundData;

  const { 
    simulatoreRisultati, 
    isEnteDissestato,
    isEnteStrutturalmenteDeficitario,
    isEnteRiequilibrioFinanziario,
  } = annualData;

  const isEnteInCondizioniSpeciali = !!isEnteDissestato || !!isEnteStrutturalmenteDeficitario || !!isEnteRiequilibrioFinanziario;
  const incrementoEQconRiduzioneDipendenti = fondoElevateQualificazioniData?.ris_incrementoConRiduzioneFondoDipendenti;

  const fadTotals = useMemo(() => calculateFadTotals(
    fondoAccessorioDipendenteData, 
    simulatoreRisultati, 
    isEnteInCondizioniSpeciali, 
    incrementoEQconRiduzioneDipendenti,
    normativeData
  ), [fondoAccessorioDipendenteData, simulatoreRisultati, isEnteInCondizioniSpeciali, incrementoEQconRiduzioneDipendenti, normativeData]);

  const totaleDaDistribuire = fadTotals.totaleRisorseDisponibiliContrattazione_Dipendenti;


  const handleChange = (field: keyof DistribuzioneRisorseData, value?: number | boolean) => {
    dispatch({ type: 'UPDATE_DISTRIBUZIONE_RISORSE_DATA', payload: { [field]: value } });
  };

  const handleVariableChange = (
    field: keyof DistribuzioneRisorseData, 
    subField: keyof RisorsaVariabileDetail, 
    value?: number
  ) => {
    if (field === 'p_maggiorazionePerformanceIndividuale' && subField === 'stanziate') {
      setIsMaggiorazioneUserEdited(true);
    }
    if (field === 'p_performanceOrganizzativa' && subField === 'stanziate') {
      setIsOrganizzativaUserEdited(true);
    }
    if (field === 'p_performanceIndividuale' && subField === 'stanziate') {
      setIsIndividualeUserEdited(true);
    }
    const currentItem = distribuzioneRisorseData[field] as RisorsaVariabileDetail | undefined;
    const newItem = {
      ...currentItem,
      [subField]: value
    };
    dispatch({ type: 'UPDATE_DISTRIBUZIONE_RISORSE_DATA', payload: { [field]: newItem } });
  };

  const handlePerfPercChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newPercStr = e.target.value;
    const newPerc = newPercStr === '' ? undefined : parseFloat(newPercStr);

    // Unlock automatic calculation when user changes the percentage
    setIsIndividualeUserEdited(false);
    setIsOrganizzativaUserEdited(false);

    dispatch({ type: 'UPDATE_DISTRIBUZIONE_RISORSE_DATA', payload: { criteri_percPerfIndividuale: newPerc }});
  };

  const utilizziParteStabile = useMemo(() => {
    const data = distribuzioneRisorseData || {};
    return (data.u_diffProgressioniStoriche || 0) +
           (data.u_indennitaComparto || 0) +
           (data.u_incrIndennitaEducatori?.stanziate || 0) +
           (data.u_incrIndennitaScolastico?.stanziate || 0) +
           (data.u_indennitaEx8QF?.stanziate || 0);
  }, [distribuzioneRisorseData]);

  const utilizziParteVariabile = useMemo(() => {
    const data = distribuzioneRisorseData || {};
    return Object.keys(data)
      .filter(key => key.startsWith('p_'))
      .reduce((sum, key) => {
          const value = data[key as keyof DistribuzioneRisorseData] as RisorsaVariabileDetail | undefined;
          return sum + (value?.stanziate || 0);
      }, 0);
  }, [distribuzioneRisorseData]);

  const totaleAllocato = useMemo(() => {
    return utilizziParteStabile + utilizziParteVariabile;
  }, [utilizziParteStabile, utilizziParteVariabile]);

  const importoRimanente = totaleDaDistribuire - totaleAllocato;

  const importoDisponibileContrattazione = useMemo(() => {
    return totaleDaDistribuire - utilizziParteStabile;
  }, [totaleDaDistribuire, utilizziParteStabile]);

  const otherVariableUtilizations = useMemo(() => {
    const data = distribuzioneRisorseData || {};
    return Object.keys(data)
      .filter(key => 
          key.startsWith('p_') && 
          key !== 'p_performanceOrganizzativa' && 
          key !== 'p_performanceIndividuale' &&
          key !== 'p_maggiorazionePerformanceIndividuale'
      )
      .reduce((sum, key) => {
          const value = data[key as keyof DistribuzioneRisorseData] as RisorsaVariabileDetail | undefined;
          return sum + (value?.stanziate || 0);
      }, 0);
  }, [distribuzioneRisorseData]);

  useEffect(() => {
    const data = distribuzioneRisorseData;
    const budgetDisponibilePerformance = Math.max(0, importoDisponibileContrattazione - otherVariableUtilizations);

    const percIndividuale = data.criteri_percPerfIndividuale ?? 0;
    const percOrganizzativa = 100 - percIndividuale;

    const updates: Partial<DistribuzioneRisorseData> = {};

    const budgetEffettivoPerformance = budgetDisponibilePerformance - (data.p_maggiorazionePerformanceIndividuale?.stanziate || 0);

    if (!isIndividualeUserEdited) {
        const calculatedIndividuale = budgetEffettivoPerformance * (percIndividuale / 100);
        const roundedIndividuale = Math.round((calculatedIndividuale + Number.EPSILON) * 100) / 100;
        const currentIndividuale = data.p_performanceIndividuale?.stanziate;

        if (currentIndividuale !== roundedIndividuale && isFinite(roundedIndividuale)) {
            updates.p_performanceIndividuale = { ...data.p_performanceIndividuale, stanziate: roundedIndividuale };
        }
    }

    if (!isOrganizzativaUserEdited) {
        const calculatedOrganizzativa = budgetEffettivoPerformance * (percOrganizzativa / 100);
        const roundedOrganizzativa = Math.round((calculatedOrganizzativa + Number.EPSILON) * 100) / 100;
        const currentOrganizzativa = data.p_performanceOrganizzativa?.stanziate;

        if (currentOrganizzativa !== roundedOrganizzativa && isFinite(roundedOrganizzativa)) {
            updates.p_performanceOrganizzativa = { ...data.p_performanceOrganizzativa, stanziate: roundedOrganizzativa };
        }
    }

    if (Object.keys(updates).length > 0) {
        dispatch({ type: 'UPDATE_DISTRIBUZIONE_RISORSE_DATA', payload: updates });
    }
  }, [
      importoDisponibileContrattazione, 
      otherVariableUtilizations,
      distribuzioneRisorseData.criteri_percPerfIndividuale,
      distribuzioneRisorseData.p_performanceIndividuale,
      distribuzioneRisorseData.p_performanceOrganizzativa,
      distribuzioneRisorseData.p_maggiorazionePerformanceIndividuale,
      isIndividualeUserEdited, 
      isOrganizzativaUserEdited, 
      dispatch
  ]);

  const distribuzioneFieldDefinitions = useMemo(() => getDistribuzioneFieldDefinitions(normativeData), [normativeData]);

  const sections = useMemo(() => 
    distribuzioneFieldDefinitions.reduce((acc, field) => {
      (acc[field.section] = acc[field.section] || []).push(field);
      return acc;
    }, {} as Record<string, typeof distribuzioneFieldDefinitions>)
  , [distribuzioneFieldDefinitions]);

  const numeroDipendenti = employees?.length || 0;
  const percDipendentiBonus = distribuzioneRisorseData.criteri_percDipendentiBonus || 0;
  const numDipendentiBonus = Math.ceil(numeroDipendenti * (percDipendentiBonus / 100));

  const maggiorazioneProCapite = useMemo(() => {
    const percInd = distribuzioneRisorseData.criteri_percPerfIndividuale || 0;
    const percMagg = distribuzioneRisorseData.criteri_percMaggiorazionePremio || 0;

    if (numeroDipendenti === 0) return 0;

    const budgetIndividualeTeorico = importoDisponibileContrattazione * (percInd / 100);
    const premioMedioTeorico = budgetIndividualeTeorico / numeroDipendenti;
    return premioMedioTeorico * (percMagg / 100);

  }, [importoDisponibileContrattazione, distribuzioneRisorseData.criteri_percPerfIndividuale, distribuzioneRisorseData.criteri_percMaggiorazionePremio, numeroDipendenti]);

  useEffect(() => {
    const calculatedValue = maggiorazioneProCapite * numDipendentiBonus;
    if (isFinite(calculatedValue)) {
        const roundedValue = Math.round((calculatedValue + Number.EPSILON) * 100) / 100;

        if (!isMaggiorazioneUserEdited) {
            const currentValue = distribuzioneRisorseData.p_maggiorazionePerformanceIndividuale?.stanziate;
            if (currentValue !== roundedValue) {
                const currentItem = distribuzioneRisorseData.p_maggiorazionePerformanceIndividuale as RisorsaVariabileDetail | undefined;
                const newItem = {
                    ...currentItem,
                    stanziate: roundedValue
                };
                dispatch({ type: 'UPDATE_DISTRIBUZIONE_RISORSE_DATA', payload: { p_maggiorazionePerformanceIndividuale: newItem } });
            }
        }
    }
  }, [maggiorazioneProCapite, numDipendentiBonus, isMaggiorazioneUserEdited, dispatch, distribuzioneRisorseData.p_maggiorazionePerformanceIndividuale]);

  // EQ Card Logic
  const eqData = fondoElevateQualificazioniData || {} as FondoElevateQualificazioniData;
  const handleEQChange = (field: keyof FondoElevateQualificazioniData, value?: number) => {
      dispatch({ type: 'UPDATE_FONDO_ELEVATE_QUALIFICAZIONI_DATA', payload: { [field]: value } });
  };
  const sommaRisorseSpecificheEQ = 
    (eqData.ris_fondoPO2017 || 0) +
    (eqData.ris_incrementoConRiduzioneFondoDipendenti || 0) +
    (eqData.ris_incrementoLimiteArt23c2_DL34 || 0) +
    (eqData.ris_incremento022MonteSalari2018 || 0) -
    (eqData.fin_art23c2_adeguamentoTetto2016 || 0);

  const sommaDistribuzioneFondoEQ = 
    (eqData.st_art17c2_retribuzionePosizione || 0) +
    (eqData.st_art17c3_retribuzionePosizioneArt16c4 || 0) +
    (eqData.st_art17c5_interimEQ || 0) +
    (eqData.st_art23c5_maggiorazioneSedi || 0) +
    (eqData.va_art17c4_retribuzioneRisultato || 0);

  const sommeNonUtilizzateEQ = sommaRisorseSpecificheEQ - sommaDistribuzioneFondoEQ;
  const minRetribuzioneRisultatoEQ = sommaRisorseSpecificheEQ * 0.15;

  let retribuzioneRisultatoInfoEQ: string | React.ReactNode = `Minimo atteso: ${formatCurrency(minRetribuzioneRisultatoEQ)}.`;
  if (eqData.va_art17c4_retribuzioneRisultato !== undefined && eqData.va_art17c4_retribuzioneRisultato < minRetribuzioneRisultatoEQ && minRetribuzioneRisultatoEQ > 0) {
      retribuzioneRisultatoInfoEQ = (
          <>
              Minimo atteso: {formatCurrency(minRetribuzioneRisultatoEQ)}.<br/>
              <strong className="text-[#c02128]">Attenzione: l'importo ├¿ inferiore al 15% delle Risorse Specifiche EQ.</strong>
          </>
      );
  } else if (minRetribuzioneRisultatoEQ <= 0 && sommaRisorseSpecificheEQ > 0) {
      retribuzioneRisultatoInfoEQ = "Calcolare prima le Risorse per le Elevate Qualificazioni per determinare il minimo.";
  } else if (sommaRisorseSpecificheEQ <= 0) {
      retribuzioneRisultatoInfoEQ = "Nessuna risorsa specifica EQ definita.";
  }

  const multiInputStableKeys: Array<keyof DistribuzioneRisorseData> = [
    'u_incrIndennitaEducatori',
    'u_incrIndennitaScolastico',
    'u_indennitaEx8QF'
  ];

  const { criteri_isConsuntivoMode } = distribuzioneRisorseData;
  const isPreventivoMode = !criteri_isConsuntivoMode;

  useEffect(() => {
    if (criteri_isConsuntivoMode === false) {
      // When switching to preventivo mode, clear risparmi and aBilancio
      const allVariableFields = distribuzioneFieldDefinitions
        .filter(def => {
            const val = distribuzioneRisorseData[def.key];
            return typeof val === 'object' && val !== null;
        })
        .map(def => def.key) as RisorsaVariabileKey[];

      const updates: Partial<DistribuzioneRisorseData> = {};
      let needsUpdate = false;

      allVariableFields.forEach(key => {
        const currentItem = distribuzioneRisorseData[key];
        if (currentItem && (currentItem.risparmi !== undefined || currentItem.aBilancio !== undefined)) {
          updates[key] = {
            ...currentItem,
            risparmi: undefined,
            aBilancio: undefined,
          };
          needsUpdate = true;
        }
      });

      if (needsUpdate) {
        dispatch({ type: 'UPDATE_DISTRIBUZIONE_RISORSE_DATA', payload: updates });
      }
    }
  }, [criteri_isConsuntivoMode, dispatch, distribuzioneRisorseData, distribuzioneFieldDefinitions]);

  const { riferimenti_normativi: norme } = normativeData;

  return (
    <div className="space-y-8 pb-24">
      <h2 className="text-[#1b0e0e] tracking-light text-2xl sm:text-[30px] font-bold leading-tight">Distribuzione delle Risorse del Fondo</h2>

      <Card title="Riepilogo Risorse e Allocazione" className="mb-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="p-4 bg-[#fcf8f8] rounded-lg text-center">
            <h4 className="text-sm font-medium text-[#5f5252]">Totale da Distribuire</h4>
            <p className="text-2xl font-bold text-[#1b0e0e]">{formatCurrency(totaleDaDistribuire)}</p>
            <p className="text-xs text-[#5f5252] mt-1">(Dal Fondo Personale Dipendente)</p>
          </div>
          <div className="p-4 bg-sky-50 rounded-lg text-center border border-sky-200">
            <h4 className="text-sm font-medium text-sky-800">Importo disponibile alla contrattazione</h4>
            <p className="text-2xl font-bold text-sky-700">{formatCurrency(importoDisponibileContrattazione)}</p>
            <p className="text-xs text-sky-600 mt-1">(Totale da Distribuire - Utilizzi Parte Stabile)</p>
          </div>
          <div className="p-4 bg-[#fcf8f8] rounded-lg text-center">
            <h4 className="text-sm font-medium text-[#5f5252]">Totale Allocato</h4>
            <p className={`text-2xl font-bold ${importoRimanente < 0 ? 'text-[#c02128]' : 'text-green-600'}`}>
              {formatCurrency(totaleAllocato)}
            </p>
            <p className="text-xs text-[#5f5252] mt-1">(Somma di tutti gli utilizzi)</p>
          </div>
          <div className={`p-4 rounded-lg text-center transition-colors ${importoRimanente < 0 ? 'bg-[#fef2f2]' : 'bg-[#f0fdf4]'}`}>
            <h4 className="text-sm font-medium text-[#5f5252]">Importo Rimanente</h4>
            <p className={`text-2xl font-bold ${importoRimanente < 0 ? 'text-[#c02128]' : 'text-green-700'}`}>
              {formatCurrency(importoRimanente)}
            </p>
            <p className="text-xs text-[#5f5252] mt-1">(Totale da Distribuire - Totale Allocato)</p>
          </div>
        </div>
        {importoRimanente < 0 && (
          <p className="text-center text-sm text-red-600 font-semibold mt-3 p-2 bg-red-50 rounded-md">
            Attenzione: l'importo allocato supera le risorse disponibili.
          </p>
        )}
      </Card>

      <Card title="Criteri di Distribuzione Performance" isCollapsible defaultCollapsed={false} className="mb-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-x-6 gap-y-4">
              <Checkbox
                id="isConsuntivoMode"
                label="Modalit├á consuntivo?"
                checked={distribuzioneRisorseData.criteri_isConsuntivoMode || false}
                onChange={(e) => handleChange('criteri_isConsuntivoMode', e.target.checked)}
                containerClassName="md:col-span-2"
              />
              <Input
                label="% Performance Individuale"
                type="number"
                id="criteri_percPerfIndividuale"
                value={distribuzioneRisorseData.criteri_percPerfIndividuale ?? ''}
                onChange={handlePerfPercChange}
                inputInfo={`% Performance Organizzativa: ${100 - (distribuzioneRisorseData.criteri_percPerfIndividuale || 0)}%`}
                min="0" max="100" step="1"
              />
              <DisplayField
                label="Budget Base Performance (calcolato)"
                value={formatCurrency(Math.max(0, importoDisponibileContrattazione - otherVariableUtilizations))}
                info="Disponibile per Contrattazione - Altri utilizzi variabili"
              />
              <Input
                label="% Maggiorazione Premio"
                type="number"
                id="criteri_percMaggiorazionePremio"
                value={distribuzioneRisorseData.criteri_percMaggiorazionePremio ?? ''}
                onChange={(e) => {
                  setIsMaggiorazioneUserEdited(false);
                  handleChange('criteri_percMaggiorazionePremio', e.target.value === '' ? undefined : parseFloat(e.target.value));
                }}
                min="0"
                max="100" 
                step="1"
                inputInfo="Il valore non pu├▓ essere inferiore al 30% del valore medio pro capite."
                warning={(distribuzioneRisorseData.criteri_percMaggiorazionePremio ?? 0) < 30 ? "Valore inferiore al minimo contrattuale del 30%." : undefined}
              />
              <Input
                label="% Dipendenti con Bonus Maggiorazione"
                type="number"
                id="criteri_percDipendentiBonus"
                value={distribuzioneRisorseData.criteri_percDipendentiBonus ?? ''}
                onChange={(e) => {
                  setIsMaggiorazioneUserEdited(false);
                  handleChange('criteri_percDipendentiBonus', e.target.value === '' ? undefined : parseFloat(e.target.value));
                }}
                min="0" max="100" step="1"
                inputInfo={`${numDipendentiBonus} su ${numeroDipendenti} dipendenti`}
              />
              <div className="md:col-span-2 mt-2">
                <DisplayField
                    label="Maggiorazione pro-capite premio individuale (calcolato)"
                    value={formatCurrency(maggiorazioneProCapite)}
                    info="((Disponibile contrattazione * % Perf. Ind.) / N┬░ Dipendenti) * % Maggiorazione"
                />
              </div>
          </div>
      </Card>

      {Object.entries(sections).map(([sectionName, fields]) => (
        <Card key={sectionName} title={sectionName} isCollapsible defaultCollapsed={sectionName.startsWith('Utilizzi Parte Variabile')}>
          {fields.map(def => {
            const isAutoCalculated = def.key === 'u_diffProgressioniStoriche' || def.key === 'u_indennitaComparto';
            const value = distribuzioneRisorseData[def.key];

            if (def.key.startsWith('u_')) {
              if (multiInputStableKeys.includes(def.key as any)) {
                return (
                    <VariableFundingItem
                      key={String(def.key)}
                      id={def.key}
                      description={def.description}
                      value={value as RisorsaVariabileDetail | undefined}
                      onChange={handleVariableChange}
                      riferimentoNormativo={def.riferimento}
                      showABilancio={false}
                      disableSavingsAndBudgetFields={isPreventivoMode}
                    />
                );
              } else {
                 return (
                    <SimpleFundingItem<DistribuzioneRisorseData>
                      key={String(def.key)}
                      id={def.key}
                      description={def.description}
                      value={value as number | undefined}
                      onChange={(field, val) => handleChange(field, val as number)}
                      riferimentoNormativo={def.riferimento}
                      disabled={isAutoCalculated}
                      inputInfo={isAutoCalculated ? "Valore calcolato automaticamente dalla pagina Personale in Servizio" : undefined}
                    />
                );
              }
            } else if (def.key.startsWith('p_')) {
              return (
                <VariableFundingItem
                  key={String(def.key)}
                  id={def.key}
                  description={def.description}
                  value={value as RisorsaVariabileDetail | undefined}
                  onChange={handleVariableChange}
                  riferimentoNormativo={def.riferimento}
                  showPercentage={true}
                  budgetBaseForPercentage={importoDisponibileContrattazione}
                  disableSavingsAndBudgetFields={isPreventivoMode}
                />
              );
            }
            return null;
          })}
        </Card>
      ))}

      <Card title="Distribuzione del fondo EQ" className="mb-6" isCollapsible={true} defaultCollapsed={true}>
        <h4 className="text-base font-bold text-[#1b0e0e] mb-2 py-3 border-b border-[#f3e7e8]">Retribuzione di Posizione (Art. 17 CCNL)</h4>
        <SimpleFundingItem<FondoElevateQualificazioniData> id="st_art17c2_retribuzionePosizione" description="LÔÇÖimporto della retribuzione di posizione varia da un minimo di Ôé¼ 5.000 ad un massimo di Ôé¼ 18.000 lordi per tredici mensilit├á, sulla base della graduazione di ciascuna posizione..." riferimentoNormativo={norme.art17_ccnl2022 + " c.2"} value={eqData.st_art17c2_retribuzionePosizione} onChange={handleEQChange} />
        <SimpleFundingItem<FondoElevateQualificazioniData> id="st_art17c3_retribuzionePosizioneArt16c4" description="Nelle ipotesi considerate nellÔÇÖart. 16, comma 4, lÔÇÖimporto della retribuzione di posizione varia da un minimo di Ôé¼ 3.000 ad un massimo di Ôé¼ 9.500 annui lordi per tredici mensilit├á." riferimentoNormativo={norme.art17_ccnl2022 + " c.3"} value={eqData.st_art17c3_retribuzionePosizioneArt16c4} onChange={handleEQChange} />
        <SimpleFundingItem<FondoElevateQualificazioniData> id="st_art17c5_interimEQ" description="NellÔÇÖipotesi di conferimento ad interim... ulteriore importo la cui misura pu├▓ variare dal 15% al 25% del valore economico della retribuzione di posizione..." riferimentoNormativo={norme.art17_ccnl2022 + " c.5"} value={eqData.st_art17c5_interimEQ} onChange={handleEQChange} />
        <SimpleFundingItem<FondoElevateQualificazioniData> id="st_art23c5_maggiorazioneSedi" description="Maggiorazione della retribuzione di posizione per servizio in diverse sedi (fino al 30%)..." riferimentoNormativo={norme.art23_c5_ccnl2022} value={eqData.st_art23c5_maggiorazioneSedi} onChange={handleEQChange} />
        <h4 className="text-base font-bold text-[#1b0e0e] mb-2 mt-6 py-3 border-b border-t border-[#f3e7e8]">Retribuzione di Risultato (Art. 17 CCNL)</h4>
        <SimpleFundingItem<FondoElevateQualificazioniData> id="va_art17c4_retribuzioneRisultato" description="Gli enti definiscono i criteri per la determinazione e per lÔÇÖerogazione annuale della retribuzione di risultato degli incarichi di EQ, destinando a tale particolare voce retributiva una quota non inferiore al 15% delle risorse complessivamente finalizzate alla erogazione della retribuzione di posizione e di risultato di tutti gli incarichi previsti dal proprio ordinamento." riferimentoNormativo={norme.art17_ccnl2022 + " c.4"} value={eqData.va_art17c4_retribuzioneRisultato} onChange={handleEQChange} inputInfo={retribuzioneRisultatoInfoEQ} />
        <SectionTotal label="SOMMA DISTRIBUZIONE FONDO EQ" total={sommaDistribuzioneFondoEQ} className="border-t-2 border-[#d1c0c1]" />
        <CalculatedDisplayItem label="Somme non utilizzate" value={sommeNonUtilizzateEQ} infoText="Calcolato come: (Somma Risorse per le Elevate Qualificazioni) - (Somma Distribuzione Fondo EQ)" isWarning={sommeNonUtilizzateEQ < 0} isBold={true}/>
      </Card>


      <div className="mt-10 flex justify-end">
        <Button 
          variant="primary" 
          size="lg" 
          onClick={saveState}
        >
          Salva Distribuzione
        </Button>
      </div>
    </div>
  );
};

// pages/FondoAccessorioDipendentePage.tsx
import React, { useEffect, useState, useMemo } from 'react'; 
import { useAppContext } from '../contexts/AppContext.tsx';
import { FondoAccessorioDipendenteData, NormativeData } from '../types.ts';
import { Card } from '../components/shared/Card.tsx';
import { TEXTS_UI } from '../constants.ts'; 
// FIX: Changed import to get the getFadFieldDefinitions function from the constant.
import { getFadFieldDefinitions } from './FondoAccessorioDipendentePageHelpers.ts';
import { calculateFadTotals } from '../logic/fundEngine.ts';
import { FundingItem } from '../components/shared/FundingItem.tsx';

const formatCurrency = (value?: number, defaultText = TEXTS_UI.notApplicable) => {
  if (value === undefined || value === null || isNaN(value)) return defaultText;
  return `Ôé¼ ${value.toLocaleString('it-IT', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
};

const SectionTotal: React.FC<{ label: string; total?: number }> = ({ label, total }) => {
  return (
    <div className="mt-4 pt-4 border-t-2 border-[#d1c0c1]">
      <div className="flex justify-between items-center">
        <span className="text-base font-bold text-[#1b0e0e]">{label}</span>
        <span className="text-lg font-bold text-[#ea2832]">
          {formatCurrency(total)}
        </span>
      </div>
    </div>
  );
};

export const FondoAccessorioDipendentePage: React.FC = () => {
  const { state, dispatch } = useAppContext();
  const { normativeData } = state;
  const data = state.fundData.fondoAccessorioDipendenteData || {} as FondoAccessorioDipendenteData;
  const { 
    simulatoreRisultati, 
    calcolatoIncrementoPNRR3,
    rispettoEquilibrioBilancioPrecedente,
    rispettoDebitoCommercialePrecedente,
    approvazioneRendicontoPrecedente,
    incidenzaSalarioAccessorioUltimoRendiconto,
    fondoStabile2016PNRR,
    isEnteDissestato,
    isEnteStrutturalmenteDeficitario,
    isEnteRiequilibrioFinanziario,
  } = state.fundData.annualData;

  const { fondoPersonaleNonDirEQ2018_Art23 } = state.fundData.historicalData;
  const { personale2018PerArt23, personaleAnnoRifPerArt23 } = state.fundData.annualData;

  const incrementoEQconRiduzioneDipendenti = state.fundData.fondoElevateQualificazioniData?.ris_incrementoConRiduzioneFondoDipendenti;

  const [pnrr3UserModified, setPnrr3UserModified] = useState(false);
  const [isArt79c1cUserModified, setIsArt79c1cUserModified] = useState(false);
  const isEnteInCondizioniSpeciali = !!isEnteDissestato || !!isEnteStrutturalmenteDeficitario || !!isEnteRiequilibrioFinanziario;
  const enteCondizioniSpecialiInfo = "Disabilitato a causa dello stato dell'ente (dissesto, deficit strutturale o riequilibrio finanziario).";

  const dipendentiEquivalenti2018_art79c1c = (personale2018PerArt23 || []).reduce((sum, emp) => {
      return sum + ((emp.partTimePercentage || 0) / 100);
  }, 0);
  const dipendentiEquivalentiAnnoRif_art79c1c = (personaleAnnoRifPerArt23 || []).reduce((sum, emp) => {
      const ptPerc = (emp.partTimePercentage || 0) / 100;
      const cedoliniRatio = emp.cedoliniEmessi !== undefined && emp.cedoliniEmessi > 0 && emp.cedoliniEmessi <= 12 ? emp.cedoliniEmessi / 12 : 0;
      return sum + (ptPerc * cedoliniRatio);
  }, 0);
  const variazioneDipendenti_art79c1c = dipendentiEquivalentiAnnoRif_art79c1c - dipendentiEquivalenti2018_art79c1c;
  let valoreMedioProCapite_art79c1c = 0;
  if ((fondoPersonaleNonDirEQ2018_Art23 || 0) > 0 && dipendentiEquivalenti2018_art79c1c > 0) {
      valoreMedioProCapite_art79c1c = (fondoPersonaleNonDirEQ2018_Art23 || 0) / dipendentiEquivalenti2018_art79c1c;
  }
  const incrementoCalcolatoPerArt79c1c = Math.max(0, valoreMedioProCapite_art79c1c * variazioneDipendenti_art79c1c);
  const roundedIncrementoArt79c1c = Math.round((incrementoCalcolatoPerArt79c1c + Number.EPSILON) * 100) / 100;

  useEffect(() => {
    if (!isArt79c1cUserModified) {
      if(data.st_art79c1c_incrementoStabileConsistenzaPers === undefined || data.st_art79c1c_incrementoStabileConsistenzaPers !== roundedIncrementoArt79c1c){
        dispatch({
            type: 'UPDATE_FONDO_ACCESSORIO_DIPENDENTE_DATA',
            payload: { st_art79c1c_incrementoStabileConsistenzaPers: isNaN(roundedIncrementoArt79c1c) ? 0 : roundedIncrementoArt79c1c }
        });
      }
    }
  }, [roundedIncrementoArt79c1c, dispatch, data.st_art79c1c_incrementoStabileConsistenzaPers, isArt79c1cUserModified]);

  const arePNRR3ConditionsMet = 
    rispettoEquilibrioBilancioPrecedente === true &&
    rispettoDebitoCommercialePrecedente === true &&
    approvazioneRendicontoPrecedente === true &&
    (incidenzaSalarioAccessorioUltimoRendiconto !== undefined && incidenzaSalarioAccessorioUltimoRendiconto <= 8) &&
    (fondoStabile2016PNRR !== undefined && fondoStabile2016PNRR > 0);
  const valoreMassimoPNRR3 = (arePNRR3ConditionsMet && calcolatoIncrementoPNRR3 !== undefined && !isNaN(calcolatoIncrementoPNRR3)) 
                            ? calcolatoIncrementoPNRR3 
                            : 0;

  useEffect(() => {
    if (!pnrr3UserModified && !isEnteInCondizioniSpeciali) { 
        let autoGeneratedValueForPNRR3 = 0;
        if (arePNRR3ConditionsMet && calcolatoIncrementoPNRR3 !== undefined && !isNaN(calcolatoIncrementoPNRR3)) {
            autoGeneratedValueForPNRR3 = calcolatoIncrementoPNRR3;
        }
        if (data.vn_dl13_art8c3_incrementoPNRR_max5stabile2016 !== autoGeneratedValueForPNRR3) {
            dispatch({
                type: 'UPDATE_FONDO_ACCESSORIO_DIPENDENTE_DATA',
                payload: { vn_dl13_art8c3_incrementoPNRR_max5stabile2016: autoGeneratedValueForPNRR3 }
            });
        }
    } else if (isEnteInCondizioniSpeciali && data.vn_dl13_art8c3_incrementoPNRR_max5stabile2016 !== 0) {
        dispatch({
            type: 'UPDATE_FONDO_ACCESSORIO_DIPENDENTE_DATA',
            payload: { vn_dl13_art8c3_incrementoPNRR_max5stabile2016: 0 }
        });
    }
  }, [arePNRR3ConditionsMet, calcolatoIncrementoPNRR3, dispatch, pnrr3UserModified, data.vn_dl13_art8c3_incrementoPNRR_max5stabile2016, isEnteInCondizioniSpeciali]);

  let displayInfoPerPNRR3 = `Valore massimo da PNRR3 (Dati Fondo): ${formatCurrency(valoreMassimoPNRR3)}`;
  if (isEnteInCondizioniSpeciali) {
    displayInfoPerPNRR3 = enteCondizioniSpecialiInfo;
  } else if (!arePNRR3ConditionsMet) {
    displayInfoPerPNRR3 = "Condizioni PNRR3 non soddisfatte o stato ente problematico. L'incremento non ├¿ applicabile.";
  }

  useEffect(() => {
    const valoreDaEQ = incrementoEQconRiduzioneDipendenti !== undefined && !isNaN(incrementoEQconRiduzioneDipendenti) 
                       ? incrementoEQconRiduzioneDipendenti 
                       : 0;
    if (data.st_riduzionePerIncrementoEQ !== valoreDaEQ) {
      dispatch({
        type: 'UPDATE_FONDO_ACCESSORIO_DIPENDENTE_DATA',
        payload: { st_riduzionePerIncrementoEQ: valoreDaEQ }
      });
    }
  }, [incrementoEQconRiduzioneDipendenti, data.st_riduzionePerIncrementoEQ, dispatch]);

  const maxIncrementoDecretoPA = simulatoreRisultati?.fase5_incrementoNettoEffettivoFondo ?? 0;
  const isIncrementoDecretoPAActive = maxIncrementoDecretoPA > 0;

  const handleChange = (field: keyof FondoAccessorioDipendenteData, value?: number) => {
    let processedValue = value;
    if (field === 'st_incrementoDecretoPA') {
      if (isIncrementoDecretoPAActive) { 
        processedValue = (value !== undefined) ? Math.min(Math.max(0, value), maxIncrementoDecretoPA) : undefined;
      } else {
        processedValue = 0; 
      }
    } else if (field === 'vn_dl13_art8c3_incrementoPNRR_max5stabile2016') {
      setPnrr3UserModified(true); 
      // FIX: Corrected typo from `isEnteInCondizioni` to `isEnteInCondizioniSpeciali`.
      if (arePNRR3ConditionsMet && !isEnteInCondizioniSpeciali) {
        const maxAllowedPNRR3 = valoreMassimoPNRR3;
        processedValue = (value !== undefined) ? Math.min(Math.max(0, value), maxAllowedPNRR3) : undefined;
      } else {
        processedValue = 0; 
      }
    } else if (field === 'st_art79c1c_incrementoStabileConsistenzaPers') {
        setIsArt79c1cUserModified(true);
        if (value !== undefined) {
            processedValue = Math.min(value, roundedIncrementoArt79c1c);
        }
    }
    dispatch({ type: 'UPDATE_FONDO_ACCESSORIO_DIPENDENTE_DATA', payload: { [field]: processedValue } });
  };

  const fadFieldDefinitions = useMemo(() => {
    if (!normativeData) return [];
    return getFadFieldDefinitions(normativeData);
  }, [normativeData]);

  useEffect(() => {
    if (isEnteInCondizioniSpeciali) {
        if (!normativeData) return;
        const fadFieldDefinitions = getFadFieldDefinitions(normativeData);
      const fieldsToReset: Partial<FondoAccessorioDipendenteData> = {};
      fadFieldDefinitions.forEach(def => {
        if (def.isDisabledByCondizioniSpeciali) {
            fieldsToReset[def.key] = def.key === 'vn_dl13_art8c3_incrementoPNRR_max5stabile2016' ? 0 : undefined;
        }
      });

      let needsUpdate = false;
      for (const key in fieldsToReset) {
          if (data[key as keyof FondoAccessorioDipendenteData] !== fieldsToReset[key as keyof FondoAccessorioDipendenteData]) {
              needsUpdate = true;
              break;
          }
      }
      if (needsUpdate) {
        dispatch({ type: 'UPDATE_FONDO_ACCESSORIO_DIPENDENTE_DATA', payload: fieldsToReset });
      }
    }
  }, [isEnteInCondizioniSpeciali, dispatch, data, normativeData]);

  const fadTotals = useMemo(() => {
      if (!normativeData) return null;
      return calculateFadTotals(data, simulatoreRisultati, isEnteInCondizioniSpeciali, incrementoEQconRiduzioneDipendenti, normativeData)
    }, [data, simulatoreRisultati, isEnteInCondizioniSpeciali, incrementoEQconRiduzioneDipendenti, normativeData]);


  const incrementoDecretoPADescription = (
    <>
      Incremento Decreto PA
      {!isIncrementoDecretoPAActive && (
        <span className="block text-xs text-[#994d51]">
          Compilare il Simulatore Incremento nella pagina "Dati Costituzione Fondo" per attivare.
        </span>
      )}
    </>
  );

  useEffect(() => {
    if(fadTotals) {
      const sommaStabiliSoggetteLimite = fadTotals.sommaStabiliSoggetteLimite;
      const totaleParzialeRisorsePerConfrontoTetto2016_calculated = sommaStabiliSoggetteLimite + fadTotals.sommaVariabiliSoggette_Dipendenti;
      if (data.cl_totaleParzialeRisorsePerConfrontoTetto2016 !== totaleParzialeRisorsePerConfrontoTetto2016_calculated) {
        dispatch({ 
          type: 'UPDATE_FONDO_ACCESSORIO_DIPENDENTE_DATA', 
          payload: { cl_totaleParzialeRisorsePerConfrontoTetto2016: isNaN(totaleParzialeRisorsePerConfrontoTetto2016_calculated) ? 0 : totaleParzialeRisorsePerConfrontoTetto2016_calculated } 
        });
      }
    }
  }, [data.cl_totaleParzialeRisorsePerConfrontoTetto2016, fadTotals, dispatch]);

  if (!normativeData || !fadTotals) {
    return <div>Caricamento dati normativi...</div>;
  }

  const renderSection = (title: string, section: 'stabili' | 'vs_soggette' | 'vn_non_soggette' | 'fin_decurtazioni' | 'cl_limiti', sectionTotal: number, totalLabel: string) => (
    <Card title={title.toUpperCase()} className="mb-6" isCollapsible={true} defaultCollapsed={true}>
        {fadFieldDefinitions.filter(def => def.section === section).map(def => {
            let currentDescription: string | React.ReactNode = def.description;
            let currentDisabled = def.isDisabledByCondizioniSpeciali && isEnteInCondizioniSpeciali;
            let currentInputInfo: string | React.ReactNode | undefined = def.isDisabledByCondizioniSpeciali && isEnteInCondizioniSpeciali ? enteCondizioniSpecialiInfo : undefined;

            if (def.key === 'st_incrementoDecretoPA') {
                currentDescription = incrementoDecretoPADescription;
                currentDisabled = !isIncrementoDecretoPAActive;
                currentInputInfo = isIncrementoDecretoPAActive ? `Max: ${formatCurrency(maxIncrementoDecretoPA, '0.00')}` : "Attivabile tramite Simulatore";
            } else if (def.key === 'vn_dl13_art8c3_incrementoPNRR_max5stabile2016') {
                currentDisabled = (!arePNRR3ConditionsMet || isEnteInCondizioniSpeciali);
                currentInputInfo = displayInfoPerPNRR3;
            } else if (def.key === 'st_art79c1c_incrementoStabileConsistenzaPers') {
                const valoreInserito = data.st_art79c1c_incrementoStabileConsistenzaPers;
                const differenza = valoreInserito !== undefined ? roundedIncrementoArt79c1c - valoreInserito : 0;
                const showAlert = isArt79c1cUserModified && differenza > 0.005;

                let infoNode: React.ReactNode = `Valore calcolato da Art.23c2 (non Dir/EQ 2018): ${formatCurrency(roundedIncrementoArt79c1c)}`;
                if (showAlert) {
                  infoNode = (
                    <>
                      {infoNode}
                      <div className="mt-1 p-2 text-sm text-[#c02128] bg-[#fef2f2] rounded-lg border border-[#fecaca]">
                        <strong>ATTENZIONE:</strong> sono inseriti {formatCurrency(differenza)} euro in meno di quanto dovrebbe essere incrementato il fondo.
                      </div>
                    </>
                  );
                }
                currentInputInfo = infoNode;
            } else if (def.key === 'st_riduzionePerIncrementoEQ'){
                currentInputInfo = "Valore derivato dal Fondo Elevate Qualificazioni. Modificare nella pagina dedicata.";
                currentDisabled = true;
            }

            return (
                <FundingItem<FondoAccessorioDipendenteData>
                    key={String(def.key)}
                    id={def.key} 
                    description={currentDescription} 
                    value={data[def.key]} 
                    onChange={handleChange} 
                    riferimentoNormativo={def.riferimento}
                    isSubtractor={def.isSubtractor}
                    disabled={currentDisabled}
                    inputInfo={currentInputInfo}
                />
            );
        })}
        <SectionTotal label={totalLabel} total={sectionTotal} />
    </Card>
  );

  return (
    <div className="space-y-8 pb-20"> 
      <h2 className="text-[#1b0e0e] tracking-light text-2xl sm:text-[30px] font-bold leading-tight">Fondo accessorio personale dipendente</h2>

      {renderSection("Fonti di Finanziamento Stabili", 'stabili', fadTotals.sommaStabili_Dipendenti, "SOMMA RISORSE STABILI")}
      {renderSection("Fonti di Finanziamento Variabili Soggette al Limite", 'vs_soggette', fadTotals.sommaVariabiliSoggette_Dipendenti, "SOMMA RISORSE VARIABILI SOGGETTE AL LIMITE")}
      {renderSection("Fonti di Finanziamento Variabili Non Soggette al Limite", 'vn_non_soggette', fadTotals.sommaVariabiliNonSoggette_Dipendenti, "SOMMA RISORSE VARIABILI NON SOGGETTE AL LIMITE")}
      {renderSection("Altre Risorse e Decurtazioni Finali", 'fin_decurtazioni', fadTotals.altreRisorseDecurtazioniFinali_Dipendenti, "SOMMA ALTRE DECURTAZIONI")}

      <Card title="CALCOLO DEL RISPETTO DEI LIMITI DEL SALARIO ACCESSORIO" className="mb-6" isCollapsible={true} defaultCollapsed={true}>
        <FundingItem<FondoAccessorioDipendenteData>
            id="cl_totaleParzialeRisorsePerConfrontoTetto2016"
            description="Totale parziale risorse disponibili per il fondo (CALCOLATO) ai fini del confronto con il tetto complessivo del salario accessorio dell'anno 2016." 
            value={data.cl_totaleParzialeRisorsePerConfrontoTetto2016} 
            onChange={() => {}} 
            riferimentoNormativo={normativeData.riferimenti_normativi.art23_dlgs75_2017} 
            disabled={true} 
            inputInfo="Valore calcolato automaticamente"
        />
        <FundingItem<FondoAccessorioDipendenteData>
            id="cl_art23c2_decurtazioneIncrementoAnnualeTetto2016" 
            description="Art. 23 c. 2 dlgs 75/2017 Eventuale decurtazione annuale rispetto il tetto complessivo del salario accessorio dell'anno 2016." 
            value={data.cl_art23c2_decurtazioneIncrementoAnnualeTetto2016} 
            onChange={handleChange} 
            riferimentoNormativo={normativeData.riferimenti_normativi.art23_dlgs75_2017} 
            isSubtractor={true} 
        />
      </Card>

      <div className="fixed bottom-0 left-0 md:left-64 right-0 p-4 bg-[#fcf8f8]/80 backdrop-blur-sm border-t border-t-[#f3e7e8] shadow-[0_-4px_10px_rgba(0,0,0,0.05)] z-20">
        <div className="max-w-[960px] mx-auto flex justify-between items-center">
            <span className="text-lg font-bold text-[#1b0e0e]">TOTALE RISORSE DISPONIBILI:</span>
            <span className="text-2xl font-bold text-[#ea2832]">
                {formatCurrency(fadTotals?.totaleRisorseDisponibiliContrattazione_Dipendenti)}
            </span>
        </div>
      </div>

    </div>
  );
};

// pages/FondoSegretarioComunalePage.tsx
import React, { useEffect } from 'react';
import { useAppContext } from '../contexts/AppContext.tsx';
import { FondoSegretarioComunaleData } from '../types.ts';
import { Card } from '../components/shared/Card.tsx';
import { TEXTS_UI } from '../constants.ts';
import { FundingItem } from '../components/shared/FundingItem.tsx';

const formatCurrency = (value?: number, defaultText = TEXTS_UI.notApplicable) => {
    if (value === undefined || value === null || isNaN(value)) return defaultText;
    return `Ôé¼ ${value.toLocaleString('it-IT', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
};

const SectionTotal: React.FC<{ label: string; total?: number, isPercentage?: boolean }> = ({ label, total, isPercentage = false }) => {
  const formatValue = () => {
    if (total === undefined || isNaN(total)) return TEXTS_UI.notApplicable;
    const formattedNumber = total.toLocaleString('it-IT', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
    return isPercentage ? `${formattedNumber}%` : `Ôé¼ ${formattedNumber}`;
  };
  return (
    <div className="mt-4 pt-4 border-t-2 border-[#d1c0c1]">
