          } as FondoAccessorioDipendenteData
        }
      };
    case 'UPDATE_FONDO_ELEVATE_QUALIFICAZIONI_DATA':
      return {
        ...state,
        fundData: {
          ...state.fundData,
          fondoElevateQualificazioniData: {
            ...state.fundData.fondoElevateQualificazioniData,
            ...action.payload,
          } as FondoElevateQualificazioniData
        }
      };
    case 'UPDATE_FONDO_SEGRETARIO_COMUNALE_DATA':
      return {
        ...state,
        fundData: {
          ...state.fundData,
          fondoSegretarioComunaleData: {
            ...state.fundData.fondoSegretarioComunaleData,
            ...action.payload,
          } as FondoSegretarioComunaleData
        }
      };
    case 'UPDATE_FONDO_DIRIGENZA_DATA':
      return {
        ...state,
        fundData: {
          ...state.fundData,
          fondoDirigenzaData: {
            ...state.fundData.fondoDirigenzaData,
            ...action.payload,
          } as FondoDirigenzaData
        }
      };
    case 'UPDATE_DISTRIBUZIONE_RISORSE_DATA':
      return {
        ...state,
        fundData: {
          ...state.fundData,
          distribuzioneRisorseData: {
            ...state.fundData.distribuzioneRisorseData,
            ...action.payload,
          } as DistribuzioneRisorseData
        }
      };
    case 'ADD_PROVENTO_SPECIFICO':
      return { ...state, fundData: { ...state.fundData, annualData: { ...state.fundData.annualData, proventiSpecifici: [...state.fundData.annualData.proventiSpecifici, action.payload] } } };
    case 'UPDATE_PROVENTO_SPECIFICO':
      {
        const updatedProventi = [...state.fundData.annualData.proventiSpecifici];
        updatedProventi[action.payload.index] = action.payload.provento;
        return { ...state, fundData: { ...state.fundData, annualData: { ...state.fundData.annualData, proventiSpecifici: updatedProventi } } };
      }
    case 'REMOVE_PROVENTO_SPECIFICO':
      {
        const filteredProventi = state.fundData.annualData.proventiSpecifici.filter((_, index) => index !== action.payload);
        return { ...state, fundData: { ...state.fundData, annualData: { ...state.fundData.annualData, proventiSpecifici: filteredProventi } } };
      }
    case 'ADD_ART23_EMPLOYEE_DETAIL':
      {
        const { yearType, detail } = action.payload;
        const key = yearType === '2018' ? 'personale2018PerArt23' : 'personaleAnnoRifPerArt23';
        const currentList = state.fundData.annualData[key] || [];
        return {
          ...state,
          fundData: {
            ...state.fundData,
            annualData: {
              ...state.fundData.annualData,
              [key]: [...currentList, detail]
            }
          }
        };
      }
    case 'UPDATE_ART23_EMPLOYEE_DETAIL':
      {
        const { yearType, detail } = action.payload;
        const key = yearType === '2018' ? 'personale2018PerArt23' : 'personaleAnnoRifPerArt23';
        const currentList = [...(state.fundData.annualData[key] || [])];
        const index = currentList.findIndex(emp => emp.id === detail.id);
        if (index !== -1) {
          currentList[index] = detail;
        }
        return {
          ...state,
          fundData: {
            ...state.fundData,
            annualData: {
              ...state.fundData.annualData,
              [key]: currentList
            }
          }
        };
      }
    case 'REMOVE_ART23_EMPLOYEE_DETAIL':
      {
        const { yearType, id } = action.payload;
        const key = yearType === '2018' ? 'personale2018PerArt23' : 'personaleAnnoRifPerArt23';
        const currentList = state.fundData.annualData[key] || [];
        const filteredList = currentList.filter((emp) => emp.id !== id);
        return {
          ...state,
          fundData: {
            ...state.fundData,
            annualData: {
              ...state.fundData.annualData,
              [key]: filteredList
            }
          }
        };
      }
    case 'ADD_PERSONALE_SERVIZIO_DETTAGLIO': {
      const newList = [...(state.personaleServizio.dettagli || []), action.payload];
      return {
        ...state,
        personaleServizio: {
          ...state.personaleServizio,
          dettagli: newList,
        },
      };
    }
    case 'UPDATE_PERSONALE_SERVIZIO_DETTAGLIO': {
      const { id, changes } = action.payload;
      const currentList = state.personaleServizio.dettagli || [];

      const updatedList = currentList.map(emp => {
        if (emp.id !== id) {
          return emp;
        }

        const updatedEmployee = { ...emp, ...changes };
        const field = Object.keys(changes)[0] as keyof PersonaleServizioDettaglio;

        if (field === 'partTimePercentage' || field === 'numeroDifferenziali') {
          const rawValue = (changes as any)[field];
          (updatedEmployee as any)[field] = rawValue === '' || rawValue === undefined || rawValue === null ? undefined : Number(rawValue);
        } else if (field === 'livelloPeoStoriche' && (changes as any)[field] === "") {
          updatedEmployee.livelloPeoStoriche = undefined;
        }

        if (field === 'fullYearService' && updatedEmployee.fullYearService) {
          updatedEmployee.assunzioneDate = undefined;
          updatedEmployee.cessazioneDate = undefined;
        }
        if (field === 'areaQualifica') {
          updatedEmployee.livelloPeoStoriche = undefined;
          updatedEmployee.numeroDifferenziali = 0;
          updatedEmployee.tipoMaggiorazione = TipoMaggiorazione.NESSUNA;
        }

        return updatedEmployee;
      });

      return {
        ...state,
        personaleServizio: {
          ...state.personaleServizio,
          dettagli: updatedList,
        },
      };
    }
    case 'REMOVE_PERSONALE_SERVIZIO_DETTAGLIO': {
      const currentList = state.personaleServizio.dettagli || [];
      const filteredList = currentList.filter(emp => emp.id !== action.payload.id);
      return {
        ...state,
        personaleServizio: {
          ...state.personaleServizio,
          dettagli: filteredList,
        },
      };
    }
    case 'SET_PERSONALE_SERVIZIO_DETTAGLI':
      return {
        ...state,
        personaleServizio: {
          ...state.personaleServizio,
          dettagli: action.payload,
        },
      };
    case 'CALCULATE_FUND_START':
      return { ...state, isLoading: true, error: undefined, validationErrors: {} };
    case 'CALCULATE_FUND_SUCCESS':
      return { ...state, isLoading: false, calculatedFund: action.payload.fund, complianceChecks: action.payload.checks, validationErrors: {} };
    case 'CALCULATE_FUND_ERROR':
      return { ...state, isLoading: false, error: action.payload, calculatedFund: undefined, complianceChecks: [] };
    case 'SET_LOADING':
      return { ...state, isLoading: action.payload };
    case 'SET_ERROR':
      return { ...state, error: action.payload };
    case 'SET_VALIDATION_ERRORS':
      return { ...state, validationErrors: action.payload };
    case 'SET_ACTIVE_TAB':
      return { ...state, activeTab: action.payload };
    // NEW ACTION to bulk update state from DB
    case 'LOAD_STATE_FROM_DB':
      return { ...state, ...action.payload, isLoading: false };
    default:
      return state;
  }
};

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { user } = useAuth(); // Get user first

  // Initialize state WITH user info if available, to avoid "Guest" flash
  const initialStateWithUser = {
    ...defaultInitialState,
    currentUser: user ? {
      id: user.id,
      name: user.email || 'Utente',
      email: user.email || '',
      role: UserRole.GUEST // Default to GUEST, DB load will update it
    } : defaultInitialState.currentUser
  };

  const [state, dispatch] = useReducer(appReducer, initialStateWithUser);
  const { data: normativeData } = useNormativeData();

  // Effect to keep user in sync if auth changes
  useEffect(() => {
    if (user) {
      if (state.currentUser.id !== user.id) {
        dispatch({
          type: 'SET_USER',
          payload: {
            id: user.id,
            name: user.email || 'Utente',
            email: user.email || '',
            role: UserRole.GUEST
          }
        });
      }
    }
  }, [user]);

  const [availableYears, setAvailableYears] = React.useState<number[]>([]);

  // Load Entities
  // Load Entities
  const loadEntities = useCallback(async () => {
    if (!user) return;
    try {
      const { data, error } = await supabase
        .from('entities')
        .select('*')
        .eq('user_id', user.id) // Only load own entities
        .order('name');

      if (error) throw error;
      dispatch({ type: 'SET_ENTITIES', payload: data || [] });

      // If there's only one entity or none selected, select the first one automatically
      if (data && data.length > 0 && !state.currentEntity) {
        dispatch({ type: 'SET_CURRENT_ENTITY', payload: data[0] });
      }
    } catch (err) {
      console.error('Error loading entities:', err);
    }
  }, [user, state.currentEntity]);

  // Load available years
  const loadAvailableYears = useCallback(async () => {
    if (!user || !state.currentEntity) return;
    try {
      const { data, error } = await supabase
        .from('user_app_state')
        .select('current_year')
        .eq('entity_id', state.currentEntity.id)
        .order('current_year', { ascending: false });

      if (error) throw error;
      if (data) {
        setAvailableYears(data.map(d => d.current_year));
      }
    } catch (err) {
      console.error('Error fetching years:', err);
    }
  }, [user, state.currentEntity]);

  // Initial Load (Entities then Years/State)
  useEffect(() => {
    if (user) {
      loadEntities();
    }
  }, [user]);

  // Load state from Supabase when user is authenticated, entity is selected, or current year changes
  useEffect(() => {
    if (!user || !state.currentEntity) return;

    loadAvailableYears();

    const fetchState = async () => {
      console.log('AppProvider: fetchState started', state.currentEntity?.name, state.currentYear);
      dispatch({ type: 'SET_LOADING', payload: true });
      try {
        const { data, error } = await supabase
          .from('user_app_state')
          .select('*')
          .eq('entity_id', state.currentEntity!.id)
          .eq('current_year', state.currentYear)
          .single();

        console.log('AppProvider: fetchState result', { data, error });

        if (error && error.code !== 'PGRST116') {
          console.error('Error fetching state:', error);
          dispatch({ type: 'SET_ERROR', payload: 'Errore nel caricamento dei dati.' });
          dispatch({ type: 'SET_LOADING', payload: false });
        } else if (data) {
          const loadedState: Partial<AppState> = {
            currentYear: data.current_year,
            currentUser: { ...state.currentUser, id: user.id, email: user.email || '', name: user.email || 'Utente', role: (data.role as UserRole) || UserRole.GUEST },
            fundData: {
              ...(data.fund_data || defaultInitialState.fundData),
              annualData: {
                ...(data.fund_data?.annualData || defaultInitialState.fundData.annualData),
                denominazioneEnte: state.currentEntity?.name || ''
              }
            },
            personaleServizio: data.personale_servizio || defaultInitialState.personaleServizio,
          };
          // @ts-ignore
          dispatch({ type: 'LOAD_STATE_FROM_DB', payload: loadedState });
        } else {
          console.log('AppProvider: No data found for year, checking for existing user profile...');

          // Set initial entity name in annual data since we are starting fresh
          if (state.currentEntity) {
            dispatch({
              type: 'UPDATE_ANNUAL_DATA',
              payload: { denominazioneEnte: state.currentEntity.name }
            });
          }

          // Fallback: Check if user exists in other years/entities to get their role
          const { data: profileData } = await supabase
            .from('user_app_state')
            .select('role, email')
            .eq('user_id', user.id)
            .order('updated_at', { ascending: false })
            .limit(1)
            .single();

          if (profileData) {
            console.log('AppProvider: Found existing profile, applying role:', profileData.role);
            dispatch({
              type: 'SET_USER',
              payload: {
                ...state.currentUser,
                id: user.id,
                email: user.email || '',
                name: user.email || 'Utente',
                role: (profileData.role as UserRole) || UserRole.GUEST
              }
            });
          }

          dispatch({ type: 'SET_LOADING', payload: false });
        }
      } catch (err) {
        console.error('Unexpected error fetching state:', err);
        dispatch({ type: 'SET_ERROR', payload: 'Errore imprevisto nel caricamento.' });
        dispatch({ type: 'SET_LOADING', payload: false });
      }
    };

    fetchState();
  }, [user, state.currentEntity, state.currentYear, loadAvailableYears]);

  const saveState = useCallback(async () => {
    if (!user || !state.currentEntity) return;

    try {
      const stateToSave = {
        user_id: user.id,
        entity_id: state.currentEntity.id,
        current_year: state.currentYear,
        email: user.email,
        role: state.currentUser.role,
        fund_data: state.fundData,
        personale_servizio: state.personaleServizio,
        updated_at: new Date().toISOString(),
      };

      const { error } = await supabase
        .from('user_app_state')
        .upsert(stateToSave, { onConflict: 'entity_id, current_year' });

      if (error) {
        console.error("Could not save state to Supabase.", error);
      } else {
        loadAvailableYears();
      }
    } catch (error) {
      console.error("Could not save state to Supabase.", error);
    }
  }, [state.currentYear, state.currentUser.role, state.fundData, state.personaleServizio, user, state.currentEntity, loadAvailableYears]);

  const createEntity = async (name: string) => {
    if (!user) return;
    try {
      const { data, error } = await supabase.from('entities').insert({ name, user_id: user.id }).select().single();
      if (error) throw error;
      if (data) {
        await loadEntities(); // Reload list
        dispatch({ type: 'SET_CURRENT_ENTITY', payload: data });
        dispatch({ type: 'SET_CURRENT_YEAR', payload: DEFAULT_CURRENT_YEAR }); // Reset year to default
      }
    } catch (err) {
      console.error("Error creating entity:", err);
      alert("Impossibile creare l'ente.");
    }
  };

  const renameEntity = async (id: string, name: string) => {
    if (!user) return;
    try {
      const { error } = await supabase.from('entities').update({ name }).eq('id', id);
      if (error) throw error;
      await loadEntities();

      if (state.currentEntity?.id === id) {
        dispatch({ type: 'SET_CURRENT_ENTITY', payload: { ...state.currentEntity, name } });
        dispatch({ type: 'UPDATE_ANNUAL_DATA', payload: { denominazioneEnte: name } });
      }
    } catch (err) {
      console.error("Error renaming entity:", err);
      alert("Impossibile rinominare l'ente.");
    }
  };

  const deleteEntity = async (id: string) => {
    if (!user) return;
    if (!confirm("Sei sicuro di voler eliminare questo ente? Tutti i dati e gli anni associati andranno persi.")) return;

    try {
      const { error: dataError } = await supabase.from('user_app_state').delete().eq('entity_id', id);
      if (dataError) throw dataError;

      const { error } = await supabase.from('entities').delete().eq('id', id);
      if (error) throw error;

      await loadEntities();

      if (state.currentEntity?.id === id) {
        window.location.reload();
      }
    } catch (err) {
      console.error("Error deleting entity:", err);
      alert("Impossibile eliminare l'ente.");
    }
  };

  const switchEntity = async (entityId: string) => {
    const entity = state.entities.find(e => e.id === entityId);
    if (entity) {
      dispatch({ type: 'SET_CURRENT_ENTITY', payload: entity });
      // Resetting year is handled in reducer or verify if we want to keep same year?
      // Usually better to reset to default or keep same if available. 
      // Current logic in reducer resets data but Year needs to be ensured.
    }
  };

  const createNewYear = async (year: number) => {
    dispatch({ type: 'SET_CURRENT_YEAR', payload: year });
    // Logic to trigger save or just switch?
    // Switching year triggers fetch, if not found uses defaults.
    // User can then save.
  };

  const performFundCalculation = useCallback(async () => {
    if (!normativeData) {
      dispatch({ type: 'CALCULATE_FUND_ERROR', payload: 'Dati normativi non caricati. Impossibile eseguire il calcolo.' });
      return;
    }

    const validationErrors = validateFundData(state.fundData);
    if (Object.keys(validationErrors).length > 0) {
      dispatch({ type: 'SET_VALIDATION_ERRORS', payload: validationErrors });
      // Do not set a generic error message, so the detailed list in DataEntryPage is shown.
      dispatch({ type: 'SET_ERROR', payload: undefined });
      dispatch({ type: 'SET_LOADING', payload: false });
      return;
    }

    dispatch({ type: 'CALCULATE_FUND_START' });
    try {
      const calculatedFund = calculateFundCompletely(state.fundData, normativeData);
      const complianceChecks = runAllComplianceChecks(calculatedFund, state.fundData, normativeData);
      dispatch({ type: 'CALCULATE_FUND_SUCCESS', payload: { fund: calculatedFund, checks: complianceChecks } });
      await saveState(); // Save after successful calculation
    } catch (e) {
      const error = e instanceof Error ? e.message : String(e);
      dispatch({ type: 'CALCULATE_FUND_ERROR', payload: `Errore nel calcolo: ${error}` });
      console.error("Calculation error:", e);
    }
  }, [state.fundData, saveState, normativeData]);

  const contextValue = {
    state,
    dispatch,
    performFundCalculation,
    saveState,
    availableYears,
    loadEntities,
    createEntity,
    renameEntity,
    deleteEntity,
    switchEntity,
    createNewYear
  };

  return (
    <AppContext.Provider value={contextValue}>
      {children}
    </AppContext.Provider>
  );
};

export const useAppContext = () => useContext(AppContext);

import React, { createContext, useContext, useEffect, useState } from 'react';
import { Session, User } from '@supabase/supabase-js';
import { supabase } from '../services/supabase';

interface AuthContextType {
    session: Session | null;
    user: User | null;
    signOut: () => Promise<void>;
    loading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [session, setSession] = useState<Session | null>(null);
    const [user, setUser] = useState<User | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        supabase.auth.getSession().then(({ data: { session } }) => {
            setSession(session);
            setUser(session?.user ?? null);
            setLoading(false);
        });

        const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
            setSession(session);
            setUser(session?.user ?? null);
            setLoading(false);
        });

        return () => subscription.unsubscribe();
    }, []);

    const signOut = async () => {
        await supabase.auth.signOut();
    };

    const value = {
        session,
        user,
        signOut,
        loading,
    };

    return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

export const useAuth = () => {
    const context = useContext(AuthContext);
    if (context === undefined) {
        throw new Error('useAuth must be used within an AuthProvider');
    }
    return context;
};

// src/logic/complianceChecks.ts
import {
  FundData,
  CalculatedFund,
  ComplianceCheck,
  DistribuzioneRisorseData,
  RisorsaVariabileDetail,
  FondoElevateQualificazioniData,
  NormativeData
} from '../types';

import { formatCurrency } from '../utils/formatters.ts';

/**
 * Verifica la corrispondenza tra le fonti di finanziamento vincolate e il loro utilizzo nella distribuzione delle risorse.
 * @param {FundData} fundData - I dati completi del fondo.
 * @returns {ComplianceCheck[]} Un array di controlli di conformit├á relativi alle risorse vincolate.
 */
const verificaCorrispondenzaRisorseVincolate = (fundData: FundData): ComplianceCheck[] => {
  const { fondoAccessorioDipendenteData, distribuzioneRisorseData } = fundData;
  const results: ComplianceCheck[] = [];

  const MAPPINGS_FONTI_USI_VINCOLATI = [
    {
      fonteKey: 'vn_art54_art67c3f_rimborsoSpeseNotifica',
      usoKey: 'p_compensiMessiNotificatori',
      descrizione: 'Corrispondenza Risorse Messi Notificatori',
      riferimento: 'Art. 54 CCNL 01.04.1999',
    },
    {
      fonteKey: 'vs_art67c3g_personaleCaseGioco',
      usoKey: 'p_compensiCaseGioco',
      descrizione: 'Corrispondenza Risorse Personale Case da Gioco',
      riferimento: 'Art. 67 c.3g CCNL 2018',
    },
    {
      fonteKey: 'vn_l145_art1c1091_incentiviRiscossioneIMUTARI',
      usoKey: 'p_incentiviIMUTARI',
      descrizione: 'Corrispondenza Risorse Incentivi IMU/TARI',
      riferimento: 'L. 145/2018 Art.1 c.1091',
    },
    {
      fonteKey: 'vn_art15c1k_art67c3c_incentiviTecniciCondoni',
      usoKeys: ['p_incentiviFunzioniTecnichePost2018', 'p_incentiviCondonoFunzioniTecnichePre2018'],
      descrizione: 'Corrispondenza Risorse Incentivi Funzioni Tecniche',
      riferimento: 'Art. 45 D.Lgs 36/2023',
    }
  ];

  for (const mapping of MAPPINGS_FONTI_USI_VINCOLATI) {
    const fonteImporto = (fondoAccessorioDipendenteData as any)[mapping.fonteKey] as number || 0;

    let usoImporto = 0;
    // @ts-ignore
    if (mapping.usoKey) {
      // @ts-ignore
      usoImporto = ((distribuzioneRisorseData as any)[mapping.usoKey] as RisorsaVariabileDetail)?.stanziate || 0;
      // @ts-ignore
    } else if (mapping.usoKeys) {
      // @ts-ignore
      usoImporto = mapping.usoKeys.reduce((sum: number, key: string) => {
        const importo = ((distribuzioneRisorseData as any)[key] as RisorsaVariabileDetail)?.stanziate || 0;
        return sum + importo;
      }, 0);
    }

    const id = `corrispondenza_${mapping.fonteKey}`;
    const valoreAttuale = `Fonte: ${formatCurrency(fonteImporto)}, Uso: ${formatCurrency(usoImporto)}`;

    if (usoImporto > fonteImporto) {
      results.push({
        id,
        descrizione: mapping.descrizione,
        isCompliant: false,
        valoreAttuale,
        limite: `Uso <= Fonte`,
        messaggio: `L'importo distribuito per questa finalit├á (${formatCurrency(usoImporto)}) supera la fonte dedicata (${formatCurrency(fonteImporto)}). Questo costituisce un'errata imputazione delle risorse.`,
        riferimentoNormativo: mapping.riferimento,
        gravita: 'error',
        relatedPage: 'distribuzioneRisorse',
      });
    } else if (fonteImporto > 0 && usoImporto < fonteImporto) {
      results.push({
        id,
        descrizione: mapping.descrizione,
        isCompliant: true,
        valoreAttuale,
        limite: `Uso <= Fonte`,
        messaggio: `Non tutte le risorse della fonte dedicata (${formatCurrency(fonteImporto)}) sono state allocate per questa finalit├á. Si suggerisce di verificare la corretta allocazione di ${formatCurrency(fonteImporto - usoImporto)}.`,
        riferimentoNormativo: mapping.riferimento,
        gravita: 'warning',
        relatedPage: 'distribuzioneRisorse',
      });
    } else {
      results.push({
        id,
        descrizione: mapping.descrizione,
        isCompliant: true,
        valoreAttuale,
        limite: `Uso <= Fonte`,
        messaggio: "Le risorse stanziate corrispondono a quelle allocate.",
        riferimentoNormativo: mapping.riferimento,
        gravita: 'info',
      });
    }
  }

  return results;
};

/**
 * Esegue tutti i controlli di conformit├á normativa sul fondo calcolato e sui dati di input.
 * @param {CalculatedFund} calculatedFund - L'oggetto del fondo calcolato.
 * @param {FundData} fundData - I dati completi inseriti dall'utente.
 * @param {NormativeData} normativeData - I dati normativi.
 * @returns {ComplianceCheck[]} Un array di oggetti che rappresentano i risultati di ogni controllo.
 */
export const runAllComplianceChecks = (calculatedFund: CalculatedFund, fundData: FundData, normativeData: NormativeData): ComplianceCheck[] => {
  let checks: ComplianceCheck[] = [];
  const { annualData, fondoAccessorioDipendenteData, fondoElevateQualificazioniData, distribuzioneRisorseData } = fundData;
  const { riferimenti_normativi } = normativeData;

  // 1. Verifica Limite Art. 23, comma 2, D.Lgs. 75/2017
  const limite2016 = calculatedFund.limiteArt23C2Modificato ?? calculatedFund.fondoBase2016;
  const ammontareSoggettoAlLimite = calculatedFund.totaleRisorseSoggetteAlLimiteDaFondiSpecifici;
  const superamento = calculatedFund.superamentoLimite2016;

  if (superamento && superamento > 0) {
    checks.push({
      id: 'limite_art23_c2',
      descrizione: "Superamento limite Art. 23 c.2 D.Lgs. 75/2017 (Fondo 2016)",
      isCompliant: false,
      valoreAttuale: formatCurrency(ammontareSoggettoAlLimite),
      limite: formatCurrency(limite2016),
      messaggio: `Rilevato superamento del limite di ${formatCurrency(superamento)}. ├ê necessario applicare una riduzione di pari importo su uno o pi├╣ fondi per rispettare il vincolo.`,
      // FIX: Casted to string to fix type error
      riferimentoNormativo: riferimenti_normativi.art23_dlgs75_2017 as string,
      gravita: 'error',
      relatedPage: 'fundDetails',
    });
  } else {
    checks.push({
      id: 'limite_art23_c2',
      descrizione: "Rispetto limite Art. 23 c.2 D.Lgs. 75/2017 (Fondo 2016)",
      isCompliant: true,
      valoreAttuale: formatCurrency(ammontareSoggettoAlLimite),
      limite: formatCurrency(limite2016),
      messaggio: "Il totale delle risorse soggette al limite dei fondi specifici rispetta il tetto storico del 2016 (come modificato).",
      // FIX: Casted to string to fix type error
      riferimentoNormativo: riferimenti_normativi.art23_dlgs75_2017 as string,
      gravita: 'info',
    });
  }

  // 2. Verifica dell'incremento per consistenza organica
  const { fondoPersonaleNonDirEQ2018_Art23 } = fundData.historicalData;
  const { personale2018PerArt23, personaleAnnoRifPerArt23 } = fundData.annualData;

  const dipendentiEquivalenti2018_art79c1c = (personale2018PerArt23 || []).reduce((sum, emp) => sum + ((emp.partTimePercentage || 100) / 100), 0);
  const dipendentiEquivalentiAnnoRif_art79c1c = (personaleAnnoRifPerArt23 || []).reduce((sum, emp) => {
    const ptPerc = (emp.partTimePercentage || 100) / 100;
    const cedoliniRatio = emp.cedoliniEmessi !== undefined && emp.cedoliniEmessi > 0 && emp.cedoliniEmessi <= 12 ? emp.cedoliniEmessi / 12 : 1;
    return sum + (ptPerc * cedoliniRatio);
  }, 0);
  const variazioneDipendenti_art79c1c = dipendentiEquivalentiAnnoRif_art79c1c - dipendentiEquivalenti2018_art79c1c;
  let valoreMedioProCapite_art79c1c = 0;
  if ((fondoPersonaleNonDirEQ2018_Art23 || 0) > 0 && dipendentiEquivalenti2018_art79c1c > 0) {
    valoreMedioProCapite_art79c1c = (fondoPersonaleNonDirEQ2018_Art23 || 0) / dipendentiEquivalenti2018_art79c1c;
  }
  const incrementoCalcolatoPerArt79c1c = Math.max(0, valoreMedioProCapite_art79c1c * variazioneDipendenti_art79c1c);
  const roundedIncremento = Math.round((incrementoCalcolatoPerArt79c1c + Number.EPSILON) * 100) / 100;

  const valoreInserito = fundData.fondoAccessorioDipendenteData?.st_art79c1c_incrementoStabileConsistenzaPers;
  const differenza = valoreInserito !== undefined ? roundedIncremento - valoreInserito : 0;

  if (roundedIncremento > 0) {
    if (valoreInserito === undefined || differenza > 0.005) {
      checks.push({
        id: 'verifica_incremento_consistenza',
        descrizione: "Verifica dell'incremento per aumento della consistenza organica",
        isCompliant: false,
        valoreAttuale: formatCurrency(valoreInserito),
        limite: `Calcolato: ${formatCurrency(roundedIncremento)}`,
        messaggio: `L'importo inserito ├¿ inferiore di ${formatCurrency(differenza)} rispetto a quanto calcolato. Si potrebbe non utilizzare a pieno le risorse disponibili per l'incremento.`,
        riferimentoNormativo: "Art. 79 c.1c CCNL 16.11.2022",
        gravita: 'warning',
        relatedPage: 'fondoAccessorioDipendente',
      });
    } else {
      checks.push({
        id: 'verifica_incremento_consistenza',
        descrizione: "Verifica dell'incremento per aumento della consistenza organica",
        isCompliant: true,
        valoreAttuale: formatCurrency(valoreInserito),
        limite: `Calcolato: ${formatCurrency(roundedIncremento)}`,
        messaggio: "L'importo inserito ├¿ conforme a quanto calcolato per l'incremento.",
        riferimentoNormativo: "Art. 79 c.1c CCNL 16.11.2022",
        gravita: 'info',
      });
    }
  }

  // Controlli che si attivano solo in modalit├á distribuzione
  if (annualData.isDistributionMode) {
    const risorseDaDistribuire = calculatedFund.dettaglioFondi.dipendente.totale;
    if (risorseDaDistribuire > 0) {
      const data = distribuzioneRisorseData || ({} as DistribuzioneRisorseData);
      const utilizziParteStabile =
        (data.u_diffProgressioniStoriche?.stanziate || 0) +
        (data.u_indennitaComparto?.stanziate || 0) +
        (data.u_incrIndennitaEducatori?.stanziate || 0) +
        (data.u_incrIndennitaScolastico?.stanziate || 0) +
        (data.u_indennitaEx8QF?.stanziate || 0);

      const utilizziParteVariabile = Object.keys(data)
        .filter(key => key.startsWith('p_'))
        .reduce((sum, key) => {
          const value = (data as any)[key] as RisorsaVariabileDetail | undefined;
          return sum + (value?.stanziate || 0);
        }, 0);

      const totaleAllocato = utilizziParteStabile + utilizziParteVariabile;
      const importoRimanente = risorseDaDistribuire - totaleAllocato;
      const importoDisponibileContrattazione = risorseDaDistribuire - utilizziParteStabile;

      if (utilizziParteStabile > risorseDaDistribuire) {
        checks.push({
          id: 'distribuzione_stabile_supera_totale',
          descrizione: "Costi Parte Stabile superano le Risorse Disponibili",
          isCompliant: false,
          valoreAttuale: formatCurrency(utilizziParteStabile),
          limite: formatCurrency(risorseDaDistribuire),
          messaggio: `I costi fissi della Parte Stabile superano il totale da distribuire. Impossibile procedere con l'allocazione della parte variabile.`,
          riferimentoNormativo: "Principi di corretta gestione finanziaria",
          gravita: 'error',
          relatedPage: 'distribuzioneRisorse',
        });
      }

      if (importoRimanente < -0.005) { // Tolleranza per errori di arrotondamento
        checks.push({
          id: 'distribuzione_superamento_budget',
          descrizione: "Superamento del budget nella Distribuzione Risorse Dipendenti",
          isCompliant: false,
          valoreAttuale: formatCurrency(totaleAllocato),
          limite: formatCurrency(risorseDaDistribuire),
          messaggio: `L'importo totale allocato per il personale dipendente supera le risorse disponibili di ${formatCurrency(Math.abs(importoRimanente))}.`,
          riferimentoNormativo: "Art. 80 CCNL 16.11.2022",
          gravita: 'error',
          relatedPage: 'distribuzioneRisorse',
        });
      } else {
        checks.push({
          id: 'distribuzione_rispetto_budget',
          descrizione: "Rispetto del budget nella Distribuzione Risorse Dipendenti",
          isCompliant: true,
          valoreAttuale: formatCurrency(totaleAllocato),
          limite: formatCurrency(risorseDaDistribuire),
          messaggio: `L'allocazione delle risorse per il personale dipendente rispetta il budget. Rimanenza: ${formatCurrency(importoRimanente)}.`,
          riferimentoNormativo: "Art. 80 CCNL 16.11.2022",
          gravita: 'info',
        });
      }

      if (importoDisponibileContrattazione > 0) {
        const pIndividuale = data.p_performanceIndividuale?.stanziate || 0;
        const pMaggiorazione = data.p_maggiorazionePerformanceIndividuale?.stanziate || 0;

        // Determiniamo il totale dei dipendenti dell'ente (dalla tab annualData/dipendenti in servizio)
        const numDipendenti = annualData.ccnl2024?.personaleInServizio01012026 ??
          annualData.personaleServizioAttuale.reduce((sum, item) => sum + (item.count || 0), 0);

        const isArt48Applicable = numDipendenti > 5;

        if (!isArt48Applicable) {
          checks.push({
            id: 'art48_applicabilita',
            descrizione: "Applicabilit├á Art. 48 (Differenziazione del premio)",
            isCompliant: true,
            valoreAttuale: `${numDipendenti} dipendenti`,
            limite: "> 5 dipendenti",
            messaggio: "L'ente ha un organico pari o inferiore a 5 dipendenti: l'istituto della differenziazione del premio (Art. 48) non trova applicazione (Errata Corrige ARAN).",
            riferimentoNormativo: "Art. 48 CCNL 2022-2024",
            gravita: 'info',
            relatedPage: 'distribuzioneRisorse',
          });
        } else {
          // Indicatore 2: Soglia minima maggiorazione
          let minPercent = 30;
          if (numDipendenti <= 10) {
            minPercent = 25;
          }
          if (data.art48_applicaObiettiviEnte) {
            minPercent = 20;
          }

          const percImpostata = data.criteri_percMaggiorazionePremio || 0;
          const isSogliaCompliant = percImpostata >= minPercent;

          checks.push({
            id: 'art48_soglia_maggiorazione',
            descrizione: "Soglia minima maggiorazione premio individuale",
            isCompliant: isSogliaCompliant,
            valoreAttuale: `${percImpostata}%`,
            limite: `ÔëÑ ${minPercent}%`,
            messaggio: isSogliaCompliant
              ? `La maggiorazione impostata per l'incentivo rispetta il vincolo contrattuale minimo (${minPercent}%).`
              : `La maggiorazione impostata (${percImpostata}%) ├¿ inferiore alla soglia contrattuale minima applicabile del ${minPercent}% in base all'organico e/o obiettivi integrati.`,
            riferimentoNormativo: "Art. 48 CCNL 2022-2024",
            gravita: isSogliaCompliant ? 'info' : 'error',
            relatedPage: 'distribuzioneRisorse',
          });

        }

        // Indicatore 4: Coerenza premio vs maggiorazione
        if (pMaggiorazione > 0 && pIndividuale === 0) {
          checks.push({
            id: 'art48_coerenza_premio',
            descrizione: "Coerenza maggiorazione performance individuale",
            isCompliant: false,
            valoreAttuale: `Premio Base: ${formatCurrency(pIndividuale)}, Maggiorazione: ${formatCurrency(pMaggiorazione)}`,
            limite: "Stanziato Base > 0",
            messaggio: "Attenzione: ├¿ stata allocata in bilancio una sommatoria per la maggiorazione del premio individuale, ma lo stanziamento del premio base risulta a zero. Verifica l'input della tabella di distribuzione.",
            riferimentoNormativo: "Coerenza di bilancio / Art. 48 CCNL 2022-2024",
            gravita: 'warning',
            relatedPage: 'distribuzioneRisorse',
          });
        }
      }
    }

    const totaleFondoEQ = calculatedFund.dettaglioFondi.eq.totale;
    if (totaleFondoEQ > 0) {
      // FIX: Casted to FondoElevateQualificazioniData to resolve type error.
      const eqData = fondoElevateQualificazioniData || ({} as FondoElevateQualificazioniData);

      const posizioneOrdinaria = eqData.st_art16c2_retribuzionePosizione || 0;
      const risultatoStanziatoEQ = eqData.va_art16c3_retribuzioneRisultato || 0;

      const sommaDistribuzioneFondoEQ = posizioneOrdinaria + risultatoStanziatoEQ;

      if (sommaDistribuzioneFondoEQ > totaleFondoEQ) {
        checks.push({
          id: 'distribuzione_eq_superamento_budget',
          descrizione: "Superamento budget nella Distribuzione Risorse EQ",
          isCompliant: false,
          valoreAttuale: formatCurrency(sommaDistribuzioneFondoEQ),
          limite: formatCurrency(totaleFondoEQ),
          messaggio: `La somma delle retribuzioni di posizione e risultato per le EQ supera il fondo disponibile di ${formatCurrency(sommaDistribuzioneFondoEQ - totaleFondoEQ)}.`,
          riferimentoNormativo: "Principi di corretta gestione finanziaria",
          gravita: 'error',
          relatedPage: 'distribuzioneRisorse',
        });
      }

      const budgetDisponibilePosRes = totaleFondoEQ;
      const minimoRisultatoEQ = budgetDisponibilePosRes * 0.15;

      if (risultatoStanziatoEQ < minimoRisultatoEQ && budgetDisponibilePosRes > 0) {
        checks.push({
          id: 'verifica_quota_minima_risultato_eq',
          descrizione: "Verifica quota minima Retribuzione di Risultato EQ",
          isCompliant: false,
          valoreAttuale: formatCurrency(risultatoStanziatoEQ),
          limite: `ÔëÑ ${formatCurrency(minimoRisultatoEQ)}`,
          messaggio: "La quota destinata alla retribuzione di risultato ├¿ inferiore al 15% delle risorse destinate complessivamente a posizione e risultato.",
          riferimentoNormativo: "CCNL 2022-2024",
          gravita: 'warning',
          relatedPage: 'distribuzioneRisorse',
        });
      }
    }

    checks = [...checks, ...verificaCorrispondenzaRisorseVincolate(fundData)];
  }

  const maxIncrementoSimulatore = annualData.simulatoreRisultati?.fase5_incrementoNettoEffettivoFondo;
  if (maxIncrementoSimulatore !== undefined && maxIncrementoSimulatore > 0) {
    const incrementoInserito = fondoAccessorioDipendenteData?.st_incrementoDecretoPA || 0;
    if (incrementoInserito > maxIncrementoSimulatore) {
      checks.push({
        id: 'coerenza_simulatore_decreto_pa',
        descrizione: "Incoerenza tra Simulatore e Incremento Decreto PA",
        isCompliant: false,
        valoreAttuale: formatCurrency(incrementoInserito),
        limite: formatCurrency(maxIncrementoSimulatore),
        messaggio: "L'incremento Decreto PA inserito nel fondo dipendenti supera il valore massimo calcolato dal simulatore.",
        riferimentoNormativo: riferimenti_normativi.art14_dl25_2025 as string,
        gravita: 'warning',
        relatedPage: 'fondoAccessorioDipendente',
      });
    }
  }

  return checks;
};

